                                GM_ADDR bias, GM_ADDR gn_gamma, GM_ADDR gn_beta,
                                GM_ADDR y,
                                uint32_t totalBatch, uint32_t outDim, uint32_t inDim,
                                uint32_t numGroups, float eps) {
