    AscendC::TQue<AscendC::TPosition::VECOUT, 1> outputBuf_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 1> tmpBuf_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 1> gnMeanBuf_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 1> gnVarBuf_;

